class ConfigurationService(maxInputSizeBytes: Int = 1024 * 1024) {

  private val allowedKeyPattern = "^[a-zA-Z0-9._\\-]+$".r
  private val allowedValueMaxLength = 10000

  def parseConfiguration(xmlString: String): Either[ConfigParseError, ParsedConfiguration] = {
    if (xmlString == null || xmlString.trim.isEmpty) {
      return Left(MalformedXmlError("Input XML string is null or empty"))
    }

    if (xmlString.getBytes("UTF-8").length > maxInputSizeBytes) {
      return Left(InputTooLargeError(maxInputSizeBytes))
    }

    val parsedXml: Elem = try {
      SecureXMLLoader.loadString(xmlString)
    } catch {
      case e: org.xml.sax.SAXParseException =>
        return Left(MalformedXmlError(s"XML parsing error: ${sanitizeErrorMessage(e.getMessage)}"))
      case e: Exception =>
        return Left(MalformedXmlError(s"Failed to parse XML: ${sanitizeErrorMessage(e.getMessage)}"))
    }

    extractConfiguration(parsedXml)
  }

  private def extractConfiguration(root: Elem): Either[ConfigParseError, ParsedConfiguration] = {
    if (root.label != "configuration") {
      return Left(ValidationError(s"Root element must be 'configuration', found '${sanitize(root.label)}'"))
    }

    val name = (root \ "@name").text.trim
    if (name.isEmpty) {
      return Left(MissingRequiredFieldError("name attribute on configuration element"))
    }

    if (!isValidIdentifier(name)) {
      return Left(ValidationError("Configuration name contains invalid characters"))
    }

    val version = (root \ "@version").text.trim match {
      case "" => None
      case v => Some(v)
    }

    val settingsResult = extractSettings(root)
    settingsResult.map { settings =>
      ParsedConfiguration(
        name = name,
        version = version,
        settings = settings
      )
    }
  }

  private def extractSettings(root: Elem): Either[ConfigParseError, List[ConfigSetting]] = {
    val sections = root \ "section"
    val topLevelSettings = root \ "setting"

    val topLevel = extractSettingsFromNodes(topLevelSettings, sectionName = None)
    val sectioned = sections.toList.flatMap { section =>
      val sectionName = (section \ "@name").text.trim
      if (sectionName.isEmpty || !isValidIdentifier(sectionName)) {
        return Left(ValidationError(s"Section has missing or invalid name"))
      }
      val sectionSettings = section \ "setting"
      extractSettingsFromNodes(sectionSettings, Some(sectionName)) match {
        case Right(s) => s
        case Left(_) => return Left(ValidationError(s"Invalid settings in section '$sectionName'"))
      }
    }

    topLevel.map(_ ++ sectioned)
  }

  private def extractSettingsFromNodes(
    nodes: scala.xml.NodeSeq,
    sectionName: Option[String]
  ): Either[ConfigParseError, List[ConfigSetting]] = {
    val results = nodes.toList.map { node =>
      val key = (node \ "@key").text.trim
      val value = node.text.trim

      if (key.isEmpty) {
        return Left(MissingRequiredFieldError("key attribute on setting element"))
      }

      if (!isValidKey(key)) {
        return Left(ValidationError(s"Setting key contains invalid characters"))
      }

      if (value.length > allowedValueMaxLength) {
        return Left(ValidationError(s"Setting value exceeds maximum length of $allowedValueMaxLength"))
      }

      ConfigSetting(
        key = key,
        value = sanitizeValue(value),
        section = sectionName
      )
    }

    Right(results)
  }

  private def isValidKey(key: String): Boolean = {
    key.length <= 256 && allowedKeyPattern.findFirstIn(key).isDefined
  }

  private def isValidIdentifier(name: String): Boolean = {
    name.length <= 256 && name.matches("^[a-zA-Z0-9._\\-\\s]+$")
  }

  private def sanitizeValue(value: String): String = {
    // Remove null bytes and control characters except newline/tab
    value.filter(c => c == '\n' || c == '\t' || c == '\r' || (c >= ' ' && c != '\u007f'))
  }

  private def sanitizeErrorMessage(msg: String): String = {
    if (msg == null) "Unknown error"
    else msg.take(500).replaceAll("[\\r\\n]", " ")
  }

  private def sanitize(input: String): String = {
    input.take(100).replaceAll("[^a-zA-Z0-9._\\-]", "_")
  }
}

// Simple HTTP-like request/response simulation for the API layer
case class ApiRequest(body: String, contentType: String)
case class ApiResponse(status: Int, body: String)

class ConfigurationApiController(service: ConfigurationService) {

  def handleParseRequest(request: ApiRequest): ApiResponse = {
    if (request.contentType != "application/xml" && request.contentType != "text/xml") {
      return ApiResponse(415, """{"error": "Unsupported media type. Expected application/xml or text/xml"}""")
    }

    if (request.body == null || request.body.trim.isEmpty) {
      return ApiResponse(400, """{"error": "Request body is empty"}""")
    }

    service.parseConfiguration(request.body) match {
      case Right(config) =>
        val settingsJson = config.settings.map { s =>
          val sectionPart = s.section.map(sec => s""", "section": "${escapeJson(sec)}"""").getOrElse("")
          s"""{"key": "${escapeJson(s.key)}", "value": "${escapeJson(s.value)}"$sectionPart}"""
        }.mkString("[", ", ", "]")

        val versionPart = config.version.map(v => s""", "version": "${escapeJson(v)}"""").getOrElse("")
        val json = s"""{"name": "${escapeJson(config.name)}"$versionPart, "settings": $settingsJson}"""
        ApiResponse(200, json)

      case Left(MalformedXmlError(msg)) =>
        ApiResponse(400, s"""{"error": "Malformed XML", "detail": "${escapeJson(msg)}"}""")

      case Left(MissingRequiredFieldError(field)) =>
        ApiResponse(400, s"""{"error": "Missing required field", "field": "${escapeJson(field)}"}""")

      case Left(ValidationError(msg)) =>
        ApiResponse(400, s"""{"error": "Validation error", "detail": "${escapeJson(msg)}"}""")

      case Left(InputTooLargeError(maxSize)) =>
        ApiResponse(413, s"""{"error": "Input too large", "maxBytes": $maxSize}""")
    }
  }

  private def escapeJson(s: String): String = {
    s.replace("\\", "\\\\")
      .replace("\"", "\\\"")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
  }
}

